"""Тесты публичного API модуля file_extract."""from __future__ import annotationsfrom src.modules.file_extract import get_supported_extensionsdef test_get_supported_extensions_returns_set() -> None:    """Публичный API возвращает поддерживаемые расширения без предварительной инициализации."""    exts = get_supported_extensions()    assert isinstance(exts, set)    assert ".pdf" in exts